# ─── MIDI / Audio: generate Jingle Bells melody using numpy ───────────────────
def note_freq(note, octave=4):
    notes = {'C': 0, 'D': 2, 'E': 4, 'F': 5, 'G': 7, 'A': 9, 'B': 11}
    semitone = notes[note] + (octave - 4) * 12
    return 440.0 * (2 ** (semitone / 12.0))

def generate_tone(freq, duration, sample_rate=44100, volume=0.3):
    t = np.linspace(0, duration, int(sample_rate * duration), endpoint=False)
    wave = (np.sin(2 * np.pi * freq * t) * 0.6 +
            np.sin(4 * np.pi * freq * t) * 0.2 +
            np.sin(6 * np.pi * freq * t) * 0.1)
    envelope = np.ones_like(t)
    attack = int(0.01 * sample_rate)
    release = int(0.05 * sample_rate)
    if attack > 0:
        envelope[:attack] = np.linspace(0, 1, attack)
    if release > 0 and release < len(t):
        envelope[-release:] = np.linspace(1, 0, release)
    wave = wave * envelope * volume
    wave = (wave * 32767).astype(np.int16)
    stereo = np.column_stack([wave, wave])
    return stereo

