# ─── Amber windows ────────────────────────────────────────────────────────────
class Window:
    def __init__(self, x, y, w, h):
        self.x = x + w // 4
        self.y = y + h // 3
        self.w = w // 3
        self.h = h // 3
        self.pulse = random.uniform(0, math.pi * 2)
        self.speed = random.uniform(1.5, 3.0)

    def draw(self, surface, t):
        brightness = 0.7 + 0.3 * math.sin(self.pulse + t * self.speed)
        color = (int(255 * brightness), int(179 * brightness), int(71 * brightness))
        pygame.draw.rect(surface, color, (self.x, self.y, self.w, self.h))
        # Glow
        glow_surf = pygame.Surface((self.w + 10, self.h + 10), pygame.SRCALPHA)
        glow_surf.fill((0, 0, 0, 0))
        pygame.draw.rect(glow_surf, (*color, 60), (0, 0, self.w + 10, self.h + 10))
        surface.blit(glow_surf, (self.x - 5, self.y - 5))

# ─── Snowflakes ───────────────────────────────────────────────────────────────
class Snowflake:
    def __init__(self):
        self.reset(start=True)

    def reset(self, start=False):
        self.x = random.uniform(0, WIDTH)
        self.y = random.uniform(-50, 0) if not start else random.uniform(0, HEIGHT)
        self.size = random.uniform(2, 8)
        self.speed = random.uniform(0.5, 2.5)
        self.drift = random.uniform(-0.3, 0.3)
        self.rotation = random.uniform(0, 360)
        self.rot_speed = random.uniform(-2, 2)
        self.shimmer = False
        self.shimmer_timer = 0
        self.color = random.choice([WHITE, PALE_BLUE, (210, 230, 255)])

    def update(self):
        self.y += self.speed
        self.x += self.drift
        self.rotation += self.rot_speed
        if random.random() < 0.002:
            self.shimmer = True
            self.shimmer_timer = 1
        if self.shimmer_timer > 0:
            self.shimmer_timer -= 1
        else:
            self.shimmer = False
        if self.y > HEIGHT + 20:
            self.reset()

    def draw(self, surface):
        color = SILVER_WHITE if self.shimmer else self.color
        cx, cy = int(self.x), int(self.y)
        r = int(self.size)
        if r < 3:
            pygame.draw.circle(surface, color, (cx, cy), r)
        else:
            # Draw snowflake arms
            for angle in range(0, 360, 60):
                rad = math.radians(angle + self.rotation)
                ex = cx + int(r * math.cos(rad))
                ey = cy + int(r * math.sin(rad))
                pygame.draw.line(surface, color, (cx, cy), (ex, ey), 1)
                # Small branches
                for branch_angle in [-30, 30]:
                    brad = math.radians(angle + self.rotation + branch_angle)
                    bx = cx + int(r * 0.5 * math.cos(rad)) + int(r * 0.3 * math.cos(brad))
                    by = cy + int(r * 0.5 * math.sin(rad)) + int(r * 0.3 * math.sin(brad))
                    pygame.draw.line(surface, color,
                                     (cx + int(r * 0.5 * math.cos(rad)),
                                      cy + int(r * 0.5 * math.sin(rad))),
                                     (bx, by), 1)

# ─── Musical notes ────────────────────────────────────────────────────────────
class MusicalNote:
    def __init__(self, t_offset=0):
        self.reset(t_offset)

    def reset(self, t_offset=0):
        self.t = t_offset
        self.speed = random.uniform(0.008, 0.015)
        self.amplitude = random.uniform(60, 120)
        self.y_base = random.uniform(HEIGHT * 0.2, HEIGHT * 0.6)
        self.size = random.randint(14, 22)
        self.rotation = 0
        self.rot_speed = random.uniform(-3, 3)
        self.symbol = random.choice(['♩', '♪', '♫', '♬'])
        self.alpha = 255
        self.color = GOLD

    def update(self):
        self.t += self.speed
        self.rotation += self.rot_speed
        if self.t > 1.2:
            self.reset(0)

    def get_pos(self):
        x = self.t * WIDTH * 1.2 - WIDTH * 0.1
        y = self.y_base + self.amplitude * math.sin(self.t * math.pi * 4)
        return int(x), int(y)

    def draw(self, surface, font):
        x, y = self.get_pos()
        if 0 <= x <= WIDTH and 0 <= y <= HEIGHT:
            alpha = min(255, int(255 * (1 - max(0, self.t - 1.0) / 0.2)))
            note_surf = font.render(self.symbol, True, GOLD)
            note_surf.set_alpha(alpha)
            surface.blit(note_surf, (x, y))

