# ─── Title text ───────────────────────────────────────────────────────────────
class TitleText:
    def __init__(self):
        self.bounce_y = 0
        self.bounce_vel = 0
        self.base_y = 60
        self.beat_timer = 0
        self.beat_interval = 0.5  # seconds

    def trigger_bounce(self):
        self.bounce_vel = -8

    def update(self, dt):
        self.bounce_vel += 0.6
        self.bounce_y += self.bounce_vel
        if self.bounce_y > 0:
            self.bounce_y = 0
            self.bounce_vel = -abs(self.bounce_vel) * 0.5
        if abs(self.bounce_vel) < 0.5 and abs(self.bounce_y) < 1:
            self.bounce_y = 0
            self.bounce_vel = 0
        self.beat_timer += dt
        if self.beat_timer >= self.beat_interval:
            self.beat_timer = 0
            self.trigger_bounce()

    def draw(self, surface, font_large, font_shadow):
        y = int(self.base_y + self.bounce_y)
        text = "Jingle Bells!"
        # Gold shadow
        shadow_surf = font_large.render(text, True, GOLD)
        surface.blit(shadow_surf, (WIDTH // 2 - shadow_surf.get_width() // 2 + 3, y + 4))
        # Red fill
        text_surf = font_large.render(text, True, DEEP_RED)
        surface.blit(text_surf, (WIDTH // 2 - text_surf.get_width() // 2, y))

# ─── Vignette / radial glow ───────────────────────────────────────────────────
def create_vignette(width, height):
    surf = pygame.Surface((width, height), pygame.SRCALPHA)
    cx, cy = width // 2, height // 2
    max_r = math.sqrt(cx ** 2 + cy ** 2)
    # Draw radial gradient from center (green tint) to edges (dark)
    for r in range(int(max_r), 0, -4):
        alpha = int(120 * (r / max_r) ** 1.5)
        color = (0, 0, 0, alpha)
        pygame.draw.circle(surf, color, (cx, cy), r)
    # Center glow (soft green)
    for r in range(200, 0, -4):
        alpha = int(30 * (1 - r / 200))
        pygame.draw.circle(surf, (80, 160, 80, alpha), (cx, cy), r)
    return surf

# ─── Fade in ──────────────────────────────────────────────────────────────────
def fade_in(surface, duration=2.0):
    fade_surf = pygame.Surface((WIDTH, HEIGHT))
    fade_surf.fill(BLACK)
    steps = int(duration * FPS)
    for i in range(steps):
        alpha = int(255 * (1 - i / steps))
        fade_surf.set_alpha(alpha)
        surface.blit(fade_surf, (0, 0))
        pygame.display.flip()
        clock.tick(FPS)
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()

